--
-- Table structure for table `order_info`
--

DROP TABLE IF EXISTS `order_info`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `order_info` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT COMMENT '订单ID',
  `order_no` varchar(50) NOT NULL COMMENT '订单编号',
  `user_id` bigint(20) unsigned NOT NULL COMMENT '用户ID',
  `movie_id` bigint(20) unsigned DEFAULT NULL COMMENT '电影ID(单片购买时)',
  `amount` decimal(10,2) NOT NULL COMMENT '金额',
  `balance_paid` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '已通过余额支付的金额',
  `order_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '订单类型(1-单片购买 2-VIP购买)',
  `status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '状态(0-未支付 1-已支付 2-已取消)',
  `pay_time` datetime DEFAULT NULL COMMENT '支付时间',
  `pay_type` tinyint(1) DEFAULT NULL COMMENT '支付类型(1-支付宝 2-微信)',
  `pay_no` varchar(100) DEFAULT NULL COMMENT '第三方支付单号',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uniq_order_no` (`order_no`),
  KEY `idx_user_id` (`user_id`),
  KEY `idx_status` (`status`),
  CONSTRAINT `fk_order_user` FOREIGN KEY (`user_id`) REFERENCES `user` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=379 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='订单表';
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `order_info`
--

LOCK TABLES `order_info` WRITE;
/*!40000 ALTER TABLE `order_info` DISABLE KEYS */;
